import { describe, it, expect } from "vitest";
import { calculatePremium } from "./premium.js";

describe("calculatePremium", () => {
  describe("empty item list", () => {
    it.todo("should return 5 G for empty item list — only processing fee (0 base + 0 first insurance + 5 fee)");
  });

  describe("single items — base premiums", () => {
    it.todo("should return 115 G for a single non-cursed non-high-enchantment sword, 0 years, first contract (100 base + 10 first insurance + 5 fee)");
    it.todo("should return 71 G for a single non-cursed amulet, 0 years, first contract (60 base + 6 first insurance + 5 fee)");
    it.todo("should return 93 G for a single non-cursed staff, 0 years, first contract (80 base + 8 first insurance + 5 fee)");
    it.todo("should return 49 G for a single non-cursed potion, 0 years, first contract (40 base + 4 first insurance + 5 fee)");
  });

  describe("components — single and multiple", () => {
    it.todo("should return 33 G for a single rune, 0 years, first contract (25 base + 2.5 first insurance = 27.5 + 5 fee = 32.5 → 33)");
    it.todo("should return 33 G for a single moonstone, 0 years, first contract (25 base + 2.5 first insurance = 27.5 + 5 fee = 32.5 → 33)");
  });

  describe("building blocks of 3 alike components", () => {
    it.todo("should return 60 G for 2 runes — no block, 0 years, first contract (50 base + 5 first insurance + 5 fee)");
    it.todo("should return 71 G for 3 runes — block applies, 0 years, first contract (60 base + 6 first insurance + 5 fee)");
    it.todo("should return 115 G for 4 runes — no block (block requires exactly 3), 0 years, first contract (100 base + 10 first insurance + 5 fee)");
    it.todo("should return 198 G for 7 runes — no block, 0 years, first contract (175 base + 17.5 first insurance = 192.5 + 5 fee = 197.5 → 198 rounded up)");
  });

  describe("\"alike\" components — same type required", () => {
    it.todo("should return 88 G for 2 runes + 1 moonstone — no block (different types), 0 years, first contract (75 base + 7.5 first insurance = 82.5 + 5 fee = 87.5 → 88)");
    it.todo("should return 137 G for 3 runes + 3 moonstones — two separate blocks, 0 years, first contract (120 base + 12 first insurance + 5 fee)");
  });

  describe("cursed items — 50% risk surcharge", () => {
    it.todo("should return 165 G for a cursed sword, 0 years, first contract (100 base + 50 curse + 10 first insurance + 5 fee)");
    it.todo("should return 101 G for a cursed amulet, 0 years, first contract (60 base + 30 curse + 6 first insurance + 5 fee)");
  });

  describe("highly enchanted items — enchantment ≥ 5 adds 30% surcharge", () => {
    it.todo("should return 145 G for a non-cursed sword enchantment 5, 0 years, first contract (100 base + 30 enchant + 10 first insurance + 5 fee)");
    it.todo("should return 115 G for a non-cursed sword enchantment 4 — no high-enchantment surcharge, 0 years, first contract (100 base + 10 first insurance + 5 fee)");
  });

  describe("both cursed and high enchantment modifiers", () => {
    it.todo("should return 195 G for a cursed sword enchantment 5, 0 years, first contract (100 base + 50 curse + 30 enchant + 10 first insurance + 5 fee)");
  });

  describe("loyalty discount — ≥ 2 years gives 20% discount", () => {
    it.todo("should return 95 G for a non-cursed sword with loyalty discount (exactly 2 years), first contract (100 base − 20 loyalty + 10 first insurance + 5 fee)");
    it.todo("should return 115 G for a non-cursed sword with 1 year — no loyalty discount, first contract (100 base + 10 first insurance + 5 fee)");
  });

  describe("first insurance surcharge — always applies", () => {
    it.todo("should return 115 G for a non-cursed sword, 0 years, first contract — first insurance 10% always applies (100 base + 10 first insurance + 5 fee)");
  });

  describe("follow-up contract discount — 15% after first contract", () => {
    it.todo("should return 100 G for a non-cursed sword, 0 years, follow-up contract (100 base − 15 follow-up + 10 first insurance + 5 fee)");
  });

  describe("modifier scope — item-specific vs policy-wide", () => {
    it.todo("should return 231 G for cursed sword + plain amulet, 0 years, first contract — curse surcharge on sword only, first insurance on policy base (160 base + 50 curse + 16 first insurance + 5 fee)");
  });

  describe("integration examples", () => {
    it.todo("should return 165 G for newcomer (0 years, first contract) with a cursed sword (100 base + 50 curse + 10 first insurance + 5 fee)");
    it.todo("should return 160 G for long-standing customer (3 years, second contract) with cursed sword enchantment 7 (100 base + 50 curse + 30 enchant − 20 loyalty + 10 first − 15 follow-up + 5 fee)");
  });

  describe("error handling", () => {
    it.todo("should throw error for unknown item type (e.g. \"broomstick\")");
  });
});

import { describe, it, expect } from "vitest";
import { processClaim } from "./claim.js";

describe("processClaim", () => {
  describe("standard reimbursement — no special clauses", () => {
    it.todo("should return payout 400 G and remainingCap 1600 G for regular sword (steel, enchantment 3), damage 500 G — full reimbursement minus 100 G deductible (500 − 100 = 400)");
    it.todo("should return payout 100 G and remainingCap 400 G for rune, damage 200 G — full reimbursement minus 100 G deductible (200 − 100 = 100)");
  });

  describe("deductible per damage event — one deductible per damaged item", () => {
    it.todo("should return payout 600 G for dragon attack damaging sword (500) and amulet (300) — 100 G deductible per item (400 + 200 = 600)");
  });

  describe("high enchantment clause — enchantment ≥ 8 reimbursed at 50%", () => {
    it.todo("should return payout 400 G for steel sword enchantment 9, damage 1000 G — 50% then deductible (500 − 100 = 400)");
  });

  describe("dragon material clause — full reimbursement", () => {
    it.todo("should return payout 700 G for dragon-material sword enchantment 5, damage 800 G — full reimbursement, then deductible (800 − 100 = 700)");
  });

  describe("both clauses — 50% rule wins over dragon material", () => {
    it.todo("should return payout 400 G for dragon-material sword enchantment 9, damage 1000 G — 50% rule wins (500 − 100 = 400)");
  });

  describe("cap — twice insurance sum", () => {
    it.todo("should have cap 3200 G for sword + amulet policy (insurance sum 1600 = 1000 + 600, cap 2×1600)");
    it.todo("should have cap 2000 G for cursed sword — cap based on unmodified insurance value 1000 (2×1000)");
    it.todo("should have insurance sum 1750 G for sword + 3 runes — block discount affects premium only, not insurance sum (1000 + 3×250)");
  });

  describe("multiple items of same type", () => {
    it.todo("should have insurance sum 2000 G and cap 4000 G for policy with two swords (2×1000)");
    it.todo("should process two sword damages with separate deductibles (500→400, 300→200 = 600 total) when two swords insured");
  });

  describe("cap exhaustion", () => {
    it.todo("should return first claim payout 1400 G, remainingCap 600 G for two successive 1500 G claims on a sword (2000 cap, 1400 payout → 600 remaining)");
    it.todo("should return second claim payout 600 G, remainingCap 0 G for two successive 1500 G claims on a sword (cap exhausted)");
  });

  describe("rounding in MHPCO's favor — payout rounds down", () => {
    it.todo("should return payout 350 G for steel sword enchantment 9, damage 901 G — 50% = 450.5, deductible 100 → 350.5 → 350 rounded down");
  });

  describe("error handling", () => {
    it.todo("should throw error when damage entry references an item type not in the policy");
    it.todo("should throw error when damages contain more entries of a type than insured (two sword damages, one sword insured)");
    it.todo("should throw error for negative damage amount");
  });
});

import { describe, it, expect } from "vitest";

describe("CLI integration", () => {
  it.todo("should process the schema example: quote an amulet then file a claim — outputs results array with premium, payout, and remainingCap");
  it.todo("should exit with non-zero status and write error to stderr for quote with unknown item type (e.g. \"broomstick\")");
  it.todo("should exit with non-zero status and write error to stderr for claim referencing an uninsured item type");
  it.todo("should exit with non-zero status and write error to stderr for negative damage amount in claim");
  it.todo("should exit with non-zero status and write error to stderr when damages contain more entries of a type than insured");
});

