export type ItemType = "sword" | "amulet" | "staff" | "potion" | "rune" | "moonstone";

export interface Item {
  type: ItemType;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export function calculatePremium(items: Item[], yearsWithMHPCO: number, isFollowUp: boolean): number {
  if (items.length === 0) return 5;
