    amulet: 60,
    staff: 80,
    potion: 40,
    rune: 25,
    moonstone: 25,
  };

  // Count components by type
  const componentCounts: Record<string, number> = {};
  let basePremium = 0;

  for (const item of items) {
    const bp = BASE_PREMIUMS[item.type];
    // Handle components with blocks
    if (item.type === "rune" || item.type === "moonstone") {
      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
    } else {
      basePremium += bp;
    }
  }

  // Apply component blocks
  for (const type of Object.keys(componentCounts)) {
    const count = componentCounts[type];
    const bp = BASE_PREMIUMS[type as ItemType];
    const blocks = Math.floor(count / 3);
    const remainder = count % 3;
    basePremium += blocks * 60 + remainder * bp;
  }

  // First insurance (always applies)
  const firstInsurance = basePremium * 0.1;

  // Total
  const total = basePremium + firstInsurance + 5;

  // Round up
